const int maxn = 63;
int n, m, mod, ans, g[maxn][maxn]; int sq[maxn], tq, fac[maxn], finv[maxn], vinv[maxn];
int modPow(int a, int x) { int s(1); for (; x; x &gt;&gt;= 1, a = _l a * a % mod) if (x &amp; 1) s = _l s * a % mod; return s; }

